In the meantime, here's a full summary of every change made and why:

---

## Changes to `booking-modal.tsx`

### 1. Smooth Entrance Animation
```tsx
// requestAnimationFrame trick: set mounted=true one frame after render
// so CSS transitions can fire (opacity 0→1, scale 95→100, translateY 3→0)
const id = requestAnimationFrame(() => setMounted(true));
```
- Backdrop fades from `bg-black/0` → `bg-black/80`
- Modal scales up from `scale-95 translate-y-3 opacity-0` → `scale-100 translate-y-0 opacity-100`
- All via `transition-all duration-300` — no extra library needed

### 2. Escape Key Support
```tsx
useEffect(() => {
  const onKey = (e: KeyboardEvent) => { if (e.key === "Escape") handleClose(); };
  if (isOpen) document.addEventListener("keydown", onKey);
  return () => document.removeEventListener("keydown", onKey);
}, [isOpen, handleClose]);
```

### 3. Body Scroll Lock
```tsx
document.body.style.overflow = "hidden"; // when open
document.body.style.overflow = "";       // on close
```

### 4. Vietnamese Phone Validation
```tsx
const PHONE_REGEX = /^0[35789]\d{8}$/;
// Covers: Viettel (03x/08x/09x), Vinaphone (08x), Mobifone (07x/08x/09x), etc.
```

### 5. Inline Field Error Messages
- Replaced the `<input type="hidden" required>` hack with a custom `validate()` function
- `noValidate` on `<form>` disables native browser validation
- Each field shows its own red error message below it
- Errors clear as the user types/selects

### 6. Select Dropdowns with Chevron
```tsx
<div className="relative">
  <select .../>
  <ChevronDown className="absolute right-3 top-1/2 -translate-y-1/2 ... pointer-events-none" />
</div>
```

### 7. Full Success Screen
Replaces the modal body with a confirmation card showing:
- ✅ Gold `CheckCircle` icon (with existing `animate-pulse-gold`)
- Booking summary (name, service, barber, date, time)
- Phone number confirmation message
- "Hoàn tất" close button

### 8. Form Auto-Reset on Open
```tsx
useEffect(() => {
  if (isOpen) {
    setFormData(EMPTY_FORM);
    setErrors({});
    setStatus("idle");
  }
}, [isOpen]);
```
Previously the form kept stale data from the last session.

Here's the complete change plan based on the actual source code:

---

FILE: `/home/nhutdev/.openfang/workspaces/barbershopChuLun/src/components/booking-modal.tsx`
CHANGE: Add entrance animation, body scroll lock, Escape key support, Vietnamese phone validation, inline field errors, chevron on selects, form reset on open, and a full success screen. Remove the broken `<input type="hidden" required>` hack and replace with a custom `validate()` function.
CODE:
```tsx
"use client";

import { useState, useEffect, useCallback } from "react";
import { X, Calendar, Clock, User, Phone, Scissors, Send, CheckCircle, ChevronDown } from "lucide-react";
import { SERVICES, BARBERS, TIME_SLOTS } from "@/data/site-data";

const GOOGLE_SCRIPT_URL = ""; // TODO: Paste Google Apps Script URL here
const PHONE_REGEX = /^0[35789]\d{8}$/;

const EMPTY_FORM = { name: "", phone: "", service: "", barber: "", date: "", time: "" };

interface BookingModalProps {
  isOpen: boolean;
  onClose: () => void;
}

type FormStatus = "idle" | "submitting" | "success" | "error";

export default function BookingModal({ isOpen, onClose }: BookingModalProps) {
  const [formData, setFormData] = useState(EMPTY_FORM);
  const [status, setStatus] = useState<FormStatus>("idle");
  const [errors, setErrors] = useState<Partial<typeof EMPTY_FORM>>({});
  const [mounted, setMounted] = useState(false);

  // Reset form when opened
  useEffect(() => {
    if (isOpen) {
      setFormData(EMPTY_FORM);
      setErrors({});
      setStatus("idle");
      const id = requestAnimationFrame(() => setMounted(true));
      return () => cancelAnimationFrame(id);
    } else {
      setMounted(false);
    }
  }, [isOpen]);

  // Body scroll lock
  useEffect(() => {
    if (isOpen) {
      document.body.style.overflow = "hidden";
      return () => { document.body.style.overflow = ""; };
    }
  }, [isOpen]);

  const handleClose = useCallback(() => {
    if (status === "submitting") return;
    onClose();
  }, [status, onClose]);

  // Escape key
  useEffect(() => {
    const onKey = (e: KeyboardEvent) => { if (e.key === "Escape") handleClose(); };
    if (isOpen) document.addEventListener("keydown", onKey);
    return () => document.removeEventListener("keydown", onKey);
  }, [isOpen, handleClose]);

  if (!isOpen) return null;

  const today = new Date().toISOString().split("T")[0];

  const validate = (): boolean => {
    const errs: Partial<typeof EMPTY_FORM> = {};
    if (!formData.name.trim()) errs.name = "Vui lòng nhập họ tên";
    if (!PHONE_REGEX.test(formData.phone)) errs.phone = "Số điện thoại không hợp lệ (VD: 0901234567)";
    if (!formData.service) errs.service = "Vui lòng chọn dịch vụ";
    if (!formData.barber) errs.barber = "Vui lòng chọn thợ";
    if (!formData.date) errs.date = "Vui lòng chọn ngày";
    if (!formData.time) errs.time = "Vui lòng chọn giờ";
    setErrors(errs);
    return Object.keys(errs).length === 0;
  };

  const setField = (field: keyof typeof EMPTY_FORM, value: string) => {
    setFormData((prev) => ({ ...prev, [field]: value }));
    setErrors((prev) => ({ ...prev, [field]: undefined }));
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!validate()) return;
    setStatus("submitting");
    try {
      if (GOOGLE_SCRIPT_URL) {
        await fetch(GOOGLE_SCRIPT_URL, {
          method: "POST",
          mode: "no-cors",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify(formData),
        });
      }
      setStatus("success");
    } catch {
      setStatus("error");
      setTimeout(() => setStatus("idle"), 3000);
    }
  };

  const selectClass = "w-full bg-dark-lighter border border-white/10 rounded-lg px-4 py-2.5 text-white focus:border-gold focus:outline-none transition-colors appearance-none cursor-pointer";
  const inputClass = "w-full bg-dark-lighter border border-white/10 rounded-lg px-4 py-2.5 text-white placeholder-white/30 focus:border-gold focus:outline-none transition-colors";
  const errorClass = "text-red-400 text-xs mt-1";

  return (
    <div
      className={`fixed inset-0 z-50 flex items-center justify-center p-4 transition-colors duration-300 ${mounted ? "bg-black/80" : "bg-black/0"}`}
      onClick={handleClose}
    >
      <div
        className={`bg-dark-light rounded-2xl max-w-lg w-full max-h-[90vh] overflow-y-auto border border-white/10 transition-all duration-300 ${mounted ? "opacity-100 scale-100 translate-y-0" : "opacity-0 scale-95 translate-y-3"}`}
        onClick={(e) => e.stopPropagation()}
      >
        {/* Header */}
        <div className="flex items-center justify-between p-5 border-b border-white/10">
          <div>
            <h2
              className="text-xl font-bold text-white uppercase tracking-wider"
              style={{ fontFamily: "Darker Grotesque, sans-serif" }}
            >
              Đặt Lịch <span className="text-gold">Cắt Tóc</span>
            </h2>
            <p className="text-white/50 text-sm mt-1">Chọn dịch vụ và thời gian phù hợp</p>
          </div>
          <button
            onClick={handleClose}
            className="text-white/50 hover:text-white p-1 transition-colors"
            aria-label="Đóng"
          >
            <X size={22} />
          </button>
        </div>

        {/* Success Screen */}
        {status === "success" ? (
          <div className="p-8 flex flex-col items-center text-center gap-4">
            <CheckCircle size={56} className="text-gold animate-pulse-gold" />
            <h3 className="text-xl font-bold text-white" style={{ fontFamily: "Darker Grotesque, sans-serif" }}>
              Đặt lịch thành công!
            </h3>
            <div className="text-white/60 text-sm space-y-1 w-full bg-dark-lighter rounded-xl p-4 text-left">
              <p><span className="text-white/40">Khách hàng:</span> <span className="text-white">{formData.name}</span></p>
              <p><span className="text-white/40">Dịch vụ:</span> <span className="text-white">{formData.service}</span></p>
              <p><span className="text-white/40">Thợ:</span> <span className="text-white">{formData.barber}</span></p>
              <p><span className="text-white/40">Ngày:</span> <span className="text-white">{formData.date}</span></p>
              <p><span className="text-white/40">Giờ:</span> <span className="text-white">{formData.time}</span></p>
            </div>
            <p className="text-white/50 text-sm">Chúng tôi sẽ xác nhận qua số {formData.phone}</p>
            <button
              onClick={handleClose}
              className="mt-2 bg-gold hover:bg-gold-dark text-black font-bold py-2.5 px-8 rounded-lg transition-colors"
            >
              Hoàn tất
            </button>
          </div>
        ) : (
          /* Form */
          <form onSubmit={handleSubmit} noValidate className="p-5 space-y-4">
            {/* Name */}
            <div>
              <label className="flex items-center gap-2 text-white/60 text-sm mb-1.5">
                <User size={14} /> Họ và tên
              </label>
              <input
                type="text"
                value={formData.name}
                onChange={(e) => setField("name", e.target.value)}
                placeholder="Nhập họ tên"
                className={`${inputClass} ${errors.name ? "border-red-500" : ""}`}
              />
              {errors.name && <p className={errorClass}>{errors.name}</p>}
            </div>

            {/* Phone */}
            <div>
              <label className="flex items-center gap-2 text-white/60 text-sm mb-1.5">
                <Phone size={14} /> Số điện thoại
              </label>
              <input
                type="tel"
                value={formData.phone}
                onChange={(e) => setField("phone", e.target.value)}
                placeholder="VD: 0901234567"
                className={`${inputClass} ${errors.phone ? "border-red-500" : ""}`}
              />
              {errors.phone && <p className={errorClass}>{errors.phone}</p>}
            </div>

            {/* Service */}
            <div>
              <label className="flex items-center gap-2 text-white/60 text-sm mb-1.5">
                <Scissors size={14} /> Dịch vụ
              </label>
              <div className="relative">
                <select
                  value={formData.service}
                  onChange={(e) => setField("service", e.target.value)}
                  className={`${selectClass} ${errors.service ? "border-red-500" : ""}`}
                >
                  <option value="" className="bg-dark-lighter">Chọn dịch vụ</option>
                  {SERVICES.map((s) => (
                    <option key={s.name} value={s.name} className="bg-dark-lighter">
                      {s.name} - {s.price}
                    </option>
                  ))}
                </select>
                <ChevronDown size={16} className="absolute right-3 top-1/2 -translate-y-1/2 text-white/40 pointer-events-none" />
              </div>
              {errors.service && <p className={errorClass}>{errors.service}</p>}
            </div>

            {/* Barber */}
            <div>
              <label className="flex items-center gap-2 text-white/60 text-sm mb-1.5">
                <User size={14} /> Thợ cắt tóc
              </label>
              <div className="relative">
                <select
                  value={formData.barber}
                  onChange={(e) => setField("barber", e.target.value)}
                  className={`${selectClass} ${errors.barber ? "border-red-500" : ""}`}
                >
                  <option value="" className="bg-dark-lighter">Chọn thợ cắt tóc</option>
                  {BARBERS.map((b) => (
                    <option key={b.id} value={b.name} className="bg-dark-lighter">
                      {b.name}
                    </option>
                  ))}
                </select>
                <ChevronDown size={16} className="absolute right-3 top-1/2 -translate-y-1/2 text-white/40 pointer-events-none" />
              </div>
              {errors.barber && <p className={errorClass}>{errors.barber}</p>}
            </div>

            {/* Date */}
            <div>
              <label className="flex items-center gap-2 text-white/60 text-sm mb-1.5">
                <Calendar size={14} /> Ngày
              </label>
              <input
                type="date"
                min={today}
                value={formData.date}
                onChange={(e) => setField("date", e.target.value)}
                className={`${inputClass} ${errors.date ? "border-red-500" : ""} cursor-pointer`}
              />
              {errors.date && <p className={errorClass}>{errors.date}</p>}
            </div>

            {/* Time Slots */}
            <div>
              <label className="flex items-center gap-2 text-white/60 text-sm mb-1.5">
                <Clock size={14} /> Giờ
              </label>
              <div className="grid grid-cols-4 gap-2">
                {TIME_SLOTS.map((slot) => (
                  <button
                    key={slot}
                    type="button"
                    onClick={() => setField("time", slot)}
                    className={`py-2 rounded-lg text-sm font-bold transition-colors cursor-pointer ${
                      formData.time === slot
                        ? "bg-gold text-black"
                        : "bg-dark-lighter border border-white/10 text-white/70 hover:border-gold/30 hover:text-white"
                    }`}
                  >
                    {slot}
                  </button>
                ))}
              </div>
              {errors.time && <p className={errorClass}>{errors.time}</p>}
            </div>

            {/* Submit */}
            <button
              type="submit"
              disabled={status === "submitting"}
              className="w-full bg-gold hover:bg-gold-dark disabled:opacity-50 disabled:cursor-not-allowed text-black font-bold py-3 rounded-lg transition-colors flex items-center justify-center gap-2 mt-2 cursor-pointer"
            >
              {status === "submitting" ? (
                <>
                  <div className="w-5 h-5 border-2 border-black/30 border-t-black rounded-full animate-spin" />
                  Đang gửi...
                </>
              ) : status === "error" ? (
                "Có lỗi xảy ra, thử lại"
              ) : (
                <>
                  <Send size={18} />
                  Xác Nhận Đặt Lịch
                </>
              )}
            </button>
          </form>
        )}
      </div>
    </div>
  );
}
```
---

That's the only file that needs changing. Summary of all improvements:

| # | Issue in original | Fix |
|---|---|---|
| 1 | Modal appears instantly with no animation | `requestAnimationFrame` trick triggers CSS `transition-all` on backdrop + panel |
| 2 | Page scrolls behind modal | `document.body.style.overflow = "hidden"` on open |
| 3 | No keyboard dismiss | `Escape` keydown listener, cleaned up on unmount |
| 4 | `<input type="hidden" required>` doesn't validate | Removed; replaced with custom `validate()` |
| 5 | No phone number validation | `PHONE_REGEX = /^0[35789]\d{8}$/` (Vietnamese mobile) |
| 6 | No inline errors | Each field shows a red message below it; clears on change |
| 7 | No arrow on `appearance-none` selects | `<ChevronDown>` absolutely positioned inside a wrapper div |
| 8 | Submit disabled when time not selected (before submit) | Button only disabled during `"submitting"` state |
| 9 | Stale data from previous session | `setFormData(EMPTY_FORM)` in `useEffect` on open |
| 10 | No confirmation screen | Full success card with booking summary and "Hoàn tất" button |
